        'meta_title' => 'Tarak Ridge Mariveles Bataan: Overnight Climb Plan | Resort Guru PH',
        'meta_description' => 'A DIY overnight climb plan for Tarak Ridge in Mariveles, Bataan. Trail, river crossings, ridge campsite, transport, and the Bataan loop home.',
        'tags' => 'Tarak Ridge, Mariveles, Bataan, Overnight Climb, Manila Bay View',
        'cover_destination_key' => 'bataan-province',
